+private struct HeaderView: View {
+    let provider: UsageProvider
+    let updatedAt: Date
+
+    var body: some View {
+        HStack(alignment: .firstTextBaseline) {
+            Text(ProviderDefaults.metadata[self.provider]?.displayName ?? self.provider.rawValue.capitalized)
+                .font(.body)
